import styles from './AudioTrack.module.css';

function AudioTrack({ objects, clips, setClips }) {
    const clipsAmount = 15;
    const sounds = [
        {
            red: '../data/sounds/red',
            green: '../data/sounds/green',
            blue: '../data/sounds/blue',
            yellow: '../data/sounds/yellow',
        },
    ];

    function playTrack() {
        const maxQueue = Math.max(...queueObjects.map(obj => obj.queue))
        const clipsInTrack = [Array.from({length: maxQueue}, (_, i) => "Empty")]
        console.log(clipsInTrack)
    }

    return (
        <div className={styles.audioTrack}>
            {Array.from({ length: clipsAmount }, (_, i) => {
                const object = objects.find((o) => o.queue === i + 1);

                return (
                    <div
                        key={i}
                        className={styles.clip}
                        style={{
                            backgroundColor: object?.color,
                        }}
                    >
                        <div
                            className={styles.queue}
                            style={{
                                backgroundColor:
                                    queueObjects.find((object) => object) &&
                                    '#1e1e1ebb',

                                borderRadius:
                                    object?.radius === '50%' ? '100%' : '5%',
                            }}
                        >
                            <p>{i + 1}</p>
                        </div>
                    </div>
                );
            })}
        </div>
    );
}

export default AudioTrack;
